output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
ASK {
  {
    SELECT(COUNT(DISTINCT ?date) AS ?count) WHERE {
      ?episode wdt:P179 wd:Q48743233 .
      ?episode wdt:P577 ?date .
    }
  }
  FILTER(?count > 1)
}

